var climbStairs = function(n, costs) {
    const INF = Infinity;
    const dp = new Array(n + 1).fill(INF);
    dp[0] = 0;
    for (let j = 1; j <= n; j++) {
        const c = costs[j - 1];
        let best = INF;
        for (const d of [1, 2, 3]) {
            const i = j - d;
            if (i >= 0 && dp[i] !== INF) {
                const cand = dp[i] + c + d * d;
                if (cand < best) best = cand;
            }
        }
        dp[j] = best;
    }
    return dp[n];
};
